def get_icon_xml(title: str) -> str:
    d = _ICON_DATA.get(title)
    if not d: return ""
    return zlib.decompress(base64.b64decode(d["gz"])).decode()


def get_icon_title(resource_type: str) -> str | None:
    k = resource_type.lower().strip()
    if k in KEY_TO_TITLE: return KEY_TO_TITLE[k]
    for rk, rt in KEY_TO_TITLE.items():
        if rk in k or k in rk: return rt
    return None


def is_container(resource_type: str) -> bool:
    k = resource_type.lower().strip()
    if k in CONTAINERS: return True
    if 'on prem' in k: return True
    return any(ck in k or k in ck for ck in CONTAINERS)


def is_gateway(resource_type: str) -> bool:
    return resource_type.lower().strip() in GATEWAY_TYPES


def get_container_style(resource_type: str) -> str:
    k = resource_type.lower().strip()
    if k in CONTAINERS: return CONTAINERS[k]
    for ck, cs in CONTAINERS.items():
        if ck in k or k in ck: return cs
    return CONTAINERS["subnet"]


def get_icon_size(title: str) -> tuple[int, int]:
    d = _ICON_DATA.get(title)
    if not d: return 64, 64
    return d["ow"], d["oh"]


def get_catalogue_summary() -> str:
    return ", ".join(sorted(list(CONTAINERS.keys()) + list(KEY_TO_TITLE.keys())))
